div.p:
c
// WRONG: Shared counter causes contention
struct {
__uint(type, BPF_MAP_TYPE_ARRAY);
__type(value, __u64);  // Single shared counter
} counter;
// CORRECT: Per-CPU eliminates contention
struct {
__uint(type, BPF_MAP_TYPE_PERCPU_ARRAY);
__type(value, __u64);  // One counter per CPU
} counter;
// Userspace must sum across CPUs:
int ncpus = libbpf_num_possible_cpus();
__u64 values[ncpus];
bpf_map_lookup_elem(fd, &key, values);
__u64 total = 0;
for (int i = 0; i < ncpus; i++)
total += values[i];
